using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Protocol;
using ModelContextProtocol.Server;

namespace McpStdioServer;

[McpServerToolType]
public sealed class ApiTools
{
    /// <summary>
    /// Fetches data from an external API endpoint and returns the JSON response.
    /// </summary>
    [McpServerTool(Name = "fetch_api"), Description("Fetches JSON data from an external HTTP API endpoint.")]
    public static async Task<CallToolResult> FetchApi(
        IHttpClientFactory httpClientFactory,
        [Description("The full URL of the API endpoint to call.")] string url,
        CancellationToken cancellationToken)
    {
        using var client = httpClientFactory.CreateClient("ExternalApi");

        using var response = await client.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        var body = await response.Content.ReadAsStringAsync(cancellationToken);

        // Pretty-print if valid JSON; return raw otherwise
        try
        {
            using var doc = JsonDocument.Parse(body);
            body = JsonSerializer.Serialize(doc, new JsonSerializerOptions { WriteIndented = true });
        }
        catch (JsonException) { }

        return new CallToolResult
        {
            Content = [new TextContentBlock { Text = body }]
        };
    }
}

using System.ComponentModel;
using ModelContextProtocol.Protocol;
using ModelContextProtocol.Server;

namespace McpStdioServer;

[McpServerPromptType]
public sealed class SummarizationPrompts
{
    [McpServerPrompt(Name = "summarize"), Description("Creates a summarization prompt for any given text.")]
    public static GetPromptResult Summarize(
        [Description("The text content to summarize.")] string text,
        [Description("Optional maximum number of sentences in the summary.")] int? maxSentences = 3)
    {
        var instruction = maxSentences.HasValue
            ? $"Summarize the following text in at most {maxSentences.Value} sentences."
            : "Summarize the following text concisely.";

        return new GetPromptResult
        {
            Description = "Summarizes the provided text.",
            Messages =
            [
                new PromptMessage
                {
                    Role = Role.User,
                    Content = new TextContentBlock
                    {
                        Text = $"{instruction}\n\n{text}"
                    }
                }
            ]
        };
    }
}

